     1→// FreeLang v6: Virtual Machine
     2→
     3→import { Op, Value, Chunk } from "./compiler";
     4→import { getBuiltins } from "./stdlib/builtins";
     5→import { JumpTable, OffsetCalculator } from "./jump-table";
     6→import { MemoryAllocator } from "./memory-allocator";
     7→import { HeapManager, TYPE_ID } from "./heap-manager";
     8→import { UnsafeManager } from "./unsafe-manager";
     9→
    10→type BuiltinFn = (args: Value[], vm: VM) => Value;
    11→type Frame = { retAddr: number; baseSlot: number; fn: string; upvalues: Value[] };
    12→type TryHandler = { catchAddr: number; stackDepth: number; frameDepth: number };
    13→type LoopContext = {
    14→  addr: number;
    15→  iterationCount: number;
    16→  // Phase 3.8: State snapshot for memory isolation
    17→  stackHeightAtEntry: number;
    18→  globalSnapshotAtEntry: Map<string, Value>;
    19→  localSnapshotAtEntry: Value[];
    20→  stateChanges: { varName: string; before: Value; after: Value }[];
    21→};
    22→
    23→export class VM {
    24→  private stack: Value[] = [];
    25→  private globals = new Map<string, Value>();
    26→  private frames: Frame[] = [];
    27→  private tryStack: TryHandler[] = [];
    28→  private ip = 0;
    29→  private output: string[] = [];
    30→  private builtinFns: Record<string, BuiltinFn>;
    31→  // Phase 8: try/catch error handling
    32→  private lastError: Value | null = null;
    33→  private inTryCall = false;
    34→  // Phase 3.7: Safety guard & iteration tracking
    35→  // Phase 3.9: Jump Table & Offset Optimization
    36→  private jumpTable: JumpTable;
    37→  private offsetCalc: OffsetCalculator = new OffsetCalculator();
    38→  // Phase 5.9: Dynamic Memory Allocator
    39→  private memoryAllocator: MemoryAllocator = new MemoryAllocator();
    40→  // STEP 1: HeapManager (v6 재설계)
    41→  private heapManager: HeapManager = new HeapManager();
    42→  // Phase 4: Unsafe 격리 레이어
    43→  private unsafeManager: UnsafeManager = new UnsafeManager();
    44→  private currentUnsafeZone: number = -1;
    45→  private unsafeDepth: number = 0;
    46→
    47→  private traceMode = false;
    48→  private traceLogs: string[] = [];
    49→  private loopStack: LoopContext[] = [];  // Track loop start positions + iteration counts
    50→  private loopDepth = 0;                   // Track nesting depth
    51→  private readonly MAX_SAFE_ITERATIONS = 1_000_000;  // Safety guard limit
    52→
    53→  constructor(private chunk: Chunk, initialGlobals?: Map<string, Value>) {
    54→    this.builtinFns = getBuiltins();
    55→    this.jumpTable = new JumpTable(this.loopStack);
    56→
    57→    // Register builtins
    58→    for (const name of Object.keys(this.builtinFns)) {
    59→      this.globals.set(name, { tag: "builtin", name });
    60→    }
    61→    // Restore persisted globals (e.g. from REPL)
    62→    if (initialGlobals) {
    63→      for (const [k, v] of initialGlobals) {
    64→        if (!this.globals.has(k)) this.globals.set(k, v);
    65→      }
    66→    }
    67→
    68→    // PHASE 3: HeapManager에 Root Collector 콜백 등록
    69→    this.heapManager.setRootCollector(() => this.getRoots());
    70→  }
    71→
    72→  getGlobals(): Map<string, Value> { return new Map(this.globals); }
    73→
    74→  run(): { output: string[]; result: Value } {
    75→    while (this.ip < this.chunk.code.length) {
    76→      const op = this.chunk.code[this.ip++];
    77→      if (op === Op.Halt) {
    78→        return { output: this.output, result: this.stack.length > 0 ? this.peek() : { tag: "null" } };
    79→      }
    80→      try {
    81→        this.execOp(op);
    82→      } catch (e) {
    83→        // If error was caught by a try handler
    84→        if (e instanceof Error && e.message.startsWith("__FREELANG_ERROR_CAUGHT__")) {
    85→          // Continue from the new IP (which should point to catch handler or finally)
    86→          continue;
    87→        }
    88→        // Re-throw unhandled errors
    89→        throw e;
    90→      }
    91→    }
    92→    return { output: this.output, result: { tag: "null" } };
    93→  }
    94→
    95→  // Public API for builtins
    96→  getGlobal(name: string): Value | undefined { return this.globals.get(name); }
    97→  setGlobal(name: string, val: Value) { this.globals.set(name, val); }
    98→  getOutput(): string[] { return this.output; }
    99→  addOutput(s: string) { this.output.push(s); }
   100→  getLastError(): Value | null { return this.lastError; }
   101→  clearLastError() { this.lastError = null; }
   102→
   103→  // Phase 5.9: Memory Allocator API for builtins
   104→  getAllocator() { return this.memoryAllocator; }
   105→
   106→  // PHASE 3: GC Root Collection
   107→  /**
   108→   * Stack, Globals, Frames에서 모든 포인터 수집 (GC Root)
   109→   */
   110→  private getRoots(): number[] {
   111→    const roots: number[] = [];
   112→
   113→    // 1. Stack의 모든 포인터 수집
   114→    this.stack.forEach(val => {
   115→      if (val.tag === "ptr") {
   116→        roots.push(val.addr);
   117→      }
   118→    });
   119→
   120→    // 2. Globals의 모든 포인터 수집
   121→    this.globals.forEach(val => {
   122→      if (val.tag === "ptr") {
   123→        roots.push(val.addr);
   124→      }
   125→    });
   126→
   127→    // 3. Frames의 upvalues 포인터 수집
   128→    this.frames.forEach(frame => {
   129→      frame.upvalues.forEach(val => {
   130→        if (val.tag === "ptr") {
   131→          roots.push(val.addr);
   132→        }
   133→      });
   134→    });
   135→
   136→    return roots;
   137→  }
   138→
   139→  // Trace mode for PC debugging
   140→  enableTrace() { this.traceMode = true; this.traceLogs = []; }
   141→  getTraceLogs(): string[] { return this.traceLogs; }
   142→
   143→  /** Call a FreeLang fn or builtin Value from within a builtin (HOFs). */
   144→  callValue(callee: Value, args: Value[]): Value {
   145→    if (callee.tag === "builtin") {
   146→      return this.builtinFns[callee.name](args, this);
   147→    }
   148→    if (callee.tag === "fn") {
   149→      const savedIp = this.ip;
   150→      const targetFrameDepth = this.frames.length;
   151→
   152→      // Mimic Call opcode: push callee + args, push frame
   153→      this.stack.push(callee);
   154→      for (const a of args) this.stack.push(a);
   155→      this.frames.push({
   156→        retAddr: savedIp,
   157→        baseSlot: this.stack.length - args.length,
   158→        fn: callee.name,
   159→        upvalues: callee.freeVars,
   160→      });
   161→      this.ip = callee.addr;
   162→
   163→      // Execute until our frame is popped by Return
   164→      try {
   165→        while (this.frames.length > targetFrameDepth) {
   166→          const op = this.chunk.code[this.ip++];
   167→          this.execOp(op);
   168→        }
   169→      } catch (e) {
   170→        // Re-throw sentinel errors so try_call can catch them
   171→        if (e instanceof Error && e.message === "__FREELANG_ERROR_CAUGHT__") {
   172→          throw e;
   173→        }
   174→        // Re-throw other errors
   175→        throw e;
   176→      }
   177→      // Return handler pushed the result onto the stack and restored ip
   178→      return this.stack.pop()!;
   179→    }
   180→    throw new Error(`Cannot call ${callee.tag}`);
   181→  }
   182→
   183→  /** Safe call for try_call builtin - captures errors as Value objects */
   184→  trySafeCall(callee: Value, args: Value[]): { ok: boolean; value?: Value; error?: Value } {
   185→    this.clearLastError();
   186→    this.inTryCall = true;
   187→
   188→    try {
   189→      if (callee.tag === "builtin") {
   190→        const retVal = this.builtinFns[callee.name](args, this);
   191→        return { ok: true, value: retVal };
   192→      }
   193→      if (callee.tag === "fn") {
   194→        const retVal = this.callValue(callee, args);
   195→        return { ok: true, value: retVal };
   196→      }
   197→      return { ok: false, error: { tag: "str", val: `Cannot call ${callee.tag}` } };
   198→    } catch (e) {
   199→      // Check if a FreeLang error occurred
   200→      if (e instanceof Error && e.message.startsWith("__FREELANG_ERROR_CAUGHT__")) {
   201→        // Return the last error that was caught
   202→        return { ok: false, error: this.lastError || { tag: "str", val: "Unknown error" } };
   203→      }
   204→      // Otherwise return string error
   205→      return { ok: false, error: { tag: "str", val: String(e) } };
   206→    } finally {
   207→      this.inTryCall = false;
   208→    }
   209→  }
   210→
   211→  stringify(v: Value): string {
   212→    switch (v.tag) {
   213→      case "num": return String(v.val);
   214→      case "str": return v.val;
   215→      case "bool": return String(v.val);
   216→      case "null": return "null";
   217→      case "array": return "[" + v.val.map(e => this.stringify(e)).join(", ") + "]";
   218→      case "object": {
   219→        const entries = Array.from(v.val.entries()).map(([k, v2]) => `${k}: ${this.stringify(v2)}`);
   220→        return "{" + entries.join(", ") + "}";
   221→      }
   222→      case "fn": return `<fn ${v.name}>`;
   223→      case "builtin": return `<builtin ${v.name}>`;
   224→      default: return "<unknown>";
   225→    }
   226→  }
   227→
   228→  // --- Private internals ---
   229→
   230→  private execOp(op: number) {
   231→    switch (op) {
   232→      case Op.Const: {
   233→        const value = this.chunk.constants[this.chunk.code[this.ip++]];
   234→        // STEP 1: HeapManager를 통한 할당 및 역참조
   235→        const heapPtr = this.valueToHeapPtr(value);
   236→        const dereferencedValue = this.heapPtrToValue(heapPtr);
   237→        this.stack.push(dereferencedValue);
   238→        break;
   239→      }
   240→      case Op.Pop: this.stack.pop(); break;
   241→      case Op.Dup: this.stack.push(this.peek()); break;
   242→
   243→      // Arithmetic
   244→      case Op.Add: {
   245→        const b = this.pop(), a = this.pop();
   246→        const result = this.add(a, b);
   247→        // STEP 3: 결과를 Heap에 할당하여 refCount 추적
   248→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   249→        break;
   250→      }
   251→      case Op.Sub: {
   252→        const b = this.popNum(), a = this.popNum();
   253→        const result = num(a - b);
   254→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   255→        break;
   256→      }
   257→      case Op.Mul: {
   258→        const b = this.popNum(), a = this.popNum();
   259→        const result = num(a * b);
   260→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   261→        break;
   262→      }
   263→      case Op.Div: {
   264→        const b = this.popNum(), a = this.popNum();
   265→        if (b === 0) this.runtimeError("Division by zero");
   266→        const result = num(a / b);
   267→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   268→        break;
   269→      }
   270→      case Op.Mod: {
   271→        const b = this.popNum(), a = this.popNum();
   272→        const result = num(a % b);
   273→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   274→        break;
   275→      }
   276→      case Op.Neg: {
   277→        const result = num(-this.popNum());
   278→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   279→        break;
   280→      }
   281→
   282→      // Comparison
   283→      case Op.Eq: {
   284→        const b = this.pop(), a = this.pop();
   285→        const result = bool(this.valEq(a, b));
   286→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   287→        break;
   288→      }
   289→      case Op.Neq: {
   290→        const b = this.pop(), a = this.pop();
   291→        const result = bool(!this.valEq(a, b));
   292→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   293→        break;
   294→      }
   295→      case Op.Lt: {
   296→        const b = this.popNum(), a = this.popNum();
   297→        const result = bool(a < b);
   298→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   299→        break;
   300→      }
   301→      case Op.Gt: {
   302→        const b = this.popNum(), a = this.popNum();
   303→        const result = bool(a > b);
   304→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   305→        break;
   306→      }
   307→      case Op.Lte: {
   308→        const b = this.popNum(), a = this.popNum();
   309→        const result = bool(a <= b);
   310→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   311→        break;
   312→      }
   313→      case Op.Gte: {
   314→        const b = this.popNum(), a = this.popNum();
   315→        const result = bool(a >= b);
   316→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   317→        break;
   318→      }
   319→
   320→      // Logic
   321→      case Op.And: {
   322→        const b = this.pop(), a = this.pop();
   323→        const result = bool(this.truthy(a) && this.truthy(b));
   324→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   325→        break;
   326→      }
   327→      case Op.Or: {
   328→        const b = this.pop(), a = this.pop();
   329→        const result = bool(this.truthy(a) || this.truthy(b));
   330→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   331→        break;
   332→      }
   333→      case Op.Not: {
   334→        const result = bool(!this.truthy(this.pop()));
   335→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(result)));
   336→        break;
   337→      }
   338→
   339→      // Jump (v3.9: Optimized with Jump Table)
   340→      case Op.Jump: {
   341→        const targetAddr = this.chunk.code[this.ip];
   342→        const offset = this.offsetCalc.calculateOffset(this.ip, targetAddr);
   343→
   344→        // Back jump = loop-back condition
   345→        if (offset < 0) {
   346→          // Find or create loop context (direct access for reliability)
   347→          let loopContext = this.loopStack.find(l => l.addr === targetAddr);
   348→
   349→          if (!loopContext) {
   350→            // First iteration: capture state snapshot for memory isolation check
   351→            const snapshot = this.captureSnapshot();
   352→            loopContext = {
   353→              addr: targetAddr,
   354→              iterationCount: 0,
   355→              stackHeightAtEntry: snapshot.stackHeight,
   356→              globalSnapshotAtEntry: snapshot.globals,
   357→              localSnapshotAtEntry: snapshot.locals,
   358→              stateChanges: [],
   359→            };
   360→            this.loopStack.push(loopContext);
   361→            this.loopDepth++;
   362→          }
   363→
   364→          // Increment iteration count
   365→          loopContext.iterationCount++;
   366→
   367→          // Safety guard: panic if exceeded
   368→          if (loopContext.iterationCount > this.MAX_SAFE_ITERATIONS) {
   369→            this.runtimeError(
   370→              `[PANIC] Safety guard triggered at loop PC ${loopContext.addr}. ` +
   371→              `Max iterations (${this.MAX_SAFE_ITERATIONS}) exceeded.`
   372→            );
   373→          }
   374→
   375→          if (this.traceMode) {
   376→            const indent = "  ".repeat(this.loopDepth);
   377→            this.traceLogs.push(
   378→              `${indent}[JUMP] PC: ${this.ip} → ${targetAddr} (loop-back, offset: ${offset}) | ` +
   379→              `Iteration: ${loopContext.iterationCount}/${this.MAX_SAFE_ITERATIONS}`
   380→            );
   381→          }
   382→        }
   383→
   384→        this.ip = targetAddr;
   385→        break;
   386→      }
   387→      case Op.JumpIfFalse: {
   388→        const addr = this.chunk.code[this.ip++];
   389→        const cond = this.pop();
   390→        const indent = "  ".repeat(this.loopDepth);
   391→
   392→        if (!this.truthy(cond)) {
   393→          // Loop condition FALSE = exit loop
   394→          if (this.loopStack.length > 0) {
   395→            const loopContext = this.loopStack[this.loopStack.length - 1];
   396→
   397→            // Phase 3.8: Compare final state with entry snapshot
   398→            const finalSnapshot = this.captureSnapshot();
   399→            const comparison = this.compareSnapshots(
   400→              {
   401→                stackHeight: loopContext.stackHeightAtEntry,
   402→                globals: loopContext.globalSnapshotAtEntry,
   403→                locals: loopContext.localSnapshotAtEntry,
   404→              },
   405→              {
   406→                stackHeight: finalSnapshot.stackHeight,
   407→                globals: finalSnapshot.globals,
   408→                locals: finalSnapshot.locals,
   409→              }
   410→            );
   411→
   412→            if (this.traceMode) {
   413→              this.traceLogs.push(
   414→                `${indent}[JUMPIF] PC: ${this.ip-1} → ${addr} (condition FALSE, exit loop) | ` +
   415→                `Final iteration count: ${loopContext.iterationCount}`
   416→              );
   417→              this.traceLogs.push(
   418→                `${indent}  └─ Stack balanced: ${comparison.stackBalanced} | ` +
   419→                `Global changes: ${comparison.globalChanges.length} | ` +
   420→                `Local corruption: ${comparison.localChanges}`
   421→              );
   422→              for (const [varName, before, after] of comparison.globalChanges) {
   423→                this.traceLogs.push(
   424→                  `${indent}     ├─ ${varName}: ${this.stringify(before)} → ${this.stringify(after)}`
   425→                );
   426→              }
   427→            }
   428→
   429→            // Store state changes for later analysis
   430→            loopContext.stateChanges = comparison.globalChanges.map(([name, before, after]) => ({
   431→              varName: name,
   432→              before,
   433→              after,
   434→            }));
   435→
   436→            this.loopStack.pop();
   437→            this.loopDepth--;
   438→            if (this.traceMode) {
   439→              this.traceLogs.push(`${indent}  └─ Loop depth: ${this.loopDepth}`);
   440→            }
   441→          }
   442→          this.ip = addr;
   443→        } else {
   444→          // Loop condition TRUE = continue looping
   445→          if (this.traceMode) {
   446→            this.traceLogs.push(`${indent}[JUMPIF] PC: ${this.ip-1} (condition TRUE, continue loop)`);
   447→          }
   448→        }
   449→        break;
   450→      }
   451→      case Op.JumpIfTrue: { const addr = this.chunk.code[this.ip++]; if (this.truthy(this.pop())) this.ip = addr; break; }
   452→
   453→      // Variables
   454→      case Op.Load: {
   455→        const slot = this.chunk.code[this.ip++];
   456→        const value = this.stack[this.baseSlot() + slot];
   457→        // STEP 4: 지역 변수를 Heap 기반으로 로드
   458→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(value)));
   459→        break;
   460→      }
   461→      case Op.Store: {
   462→        const slot = this.chunk.code[this.ip++];
   463→        const value = this.peek();
   464→        // STEP 4: 지역 변수를 Heap에 할당하여 저장
   465→        this.stack[this.baseSlot() + slot] = this.heapPtrToValue(this.valueToHeapPtr(value));
   466→        break;
   467→      }
   468→      case Op.LoadGlobal: {
   469→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   470→        const val = this.globals.get(name.val);
   471→        if (val === undefined) this.runtimeError(`Undefined variable '${name.val}'`);
   472→        // STEP 2: HeapManager 통합 - 글로벌 변수는 heap 기반으로 관리됨
   473→        // PHASE 3 수정: 포인터면 역참조하여 실제 값으로 반환
   474→        // 단, iterator는 상태 유지가 필요하므로 포인터 역참조 대상에서 제외
   475→        this.stack.push(val!.tag === "ptr" ? this.heapPtrToValue(val!) : val!);
   476→        break;
   477→      }
   478→      case Op.StoreGlobal: {
   479→        const name = this.chunk.constants[this.chunk.code[this.ip++]] as { tag: "str"; val: string };
   480→        const value = this.pop();
   481→        // STEP 2: HeapManager 통합 - 글로벌 변수를 heap에 할당
   482→        // PHASE 3 수정: 포인터를 globals에 직접 저장하여 GC root로 추적 가능하게
   483→        // 단, iterator는 상태 변화가 필요하므로 포인터로 변환하지 않음
   484→        if (value.tag === "iter") {
   485→          this.globals.set(name.val, value);
   486→        } else {
   487→          const heapPtr = this.valueToHeapPtr(value);
   488→          this.globals.set(name.val, heapPtr);
   489→        }
   490→        break;
   491→      }
   492→
   493→      // Functions
   494→      case Op.Call: {
   495→        const argc = this.chunk.code[this.ip++];
   496→        const callee = this.stack[this.stack.length - 1 - argc];
   497→        if (callee.tag === "fn") {
   498→          this.frames.push({ retAddr: this.ip, baseSlot: this.stack.length - argc, fn: callee.name, upvalues: callee.freeVars });
   499→          this.ip = callee.addr;
   500→        } else if (callee.tag === "builtin") {
   501→          const args = this.stack.splice(this.stack.length - argc, argc);
   502→          this.stack.pop(); // pop callee
   503→          const result = this.builtinFns[callee.name](args, this);
   504→          this.stack.push(result);
   505→        } else {
   506→          this.runtimeError(`Cannot call ${callee.tag}`);
   507→        }
   508→        break;
   509→      }
   510→      case Op.Return: {
   511→        const result = this.pop();
   512→        const frame = this.frames.pop()!;
   513→        this.stack.length = frame.baseSlot - 1; // remove locals + callee
   514→        this.stack.push(result);
   515→        this.ip = frame.retAddr;
   516→
   517→        // Safety: clear loop stack when returning from function
   518→        // (loops should not escape function boundaries)
   519→        if (this.frames.length === 0 && this.loopStack.length > 0) {
   520→          this.loopStack = [];
   521→          this.loopDepth = 0;
   522→        }
   523→        break;
   524→      }
