   920→  private valEq(a: Value, b: Value): boolean {
   921→    if (a.tag !== b.tag) return false;
   922→    if (a.tag === "null") return true;
   923→    if (a.tag === "num" || a.tag === "str" || a.tag === "bool") return (a as any).val === (b as any).val;
   924→    return a === b;
