   927→  private truthy(v: Value): boolean {
   928→    if (v.tag === "null") return false;
   929→    if (v.tag === "bool") return v.val;
   930→    if (v.tag === "num") return v.val !== 0;
   931→    if (v.tag === "str") return v.val !== "";
   932→    if (v.tag === "array") return v.val.length > 0;
   933→    return true;
