  1008→  /**
  1009→   * STEP 1: Ptr Value에서 실제 값으로 역참조
  1010→   */
  1011→  private heapPtrToValue(ptrValue: Value): Value {
  1012→    if (ptrValue.tag !== "ptr") {
  1013→      // 이미 실제 값이면 그대로 반환
  1014→      return ptrValue;
  1015→    }
  1016→
  1017→    const ptr = ptrValue.addr;
  1018→    const heapObj = this.heapManager.get(ptr);
  1019→    if (!heapObj) {
  1020→      this.runtimeError(`Invalid pointer: ${ptr}`);
  1021→    }
  1022→
  1023→    // HeapObject를 Value로 변환
  1024→    const typeId = heapObj!.typeId;
  1025→    const payload = heapObj!.payload;
  1026→
  1027→    switch (typeId) {
  1028→      case TYPE_ID.NUM:
  1029→        return { tag: "num", val: payload };
  1030→      case TYPE_ID.STR:
  1031→        return { tag: "str", val: payload };
  1032→      case TYPE_ID.BOOL:
  1033→        return { tag: "bool", val: payload };
  1034→      case TYPE_ID.NULL:
  1035→        return { tag: "null" };
  1036→      case TYPE_ID.ARRAY:
  1037→        return { tag: "array", val: payload };
  1038→      case TYPE_ID.OBJECT:
  1039→        return { tag: "object", val: payload };
  1040→      case TYPE_ID.FN:
  1041→        return payload as Value; // 이미 fn 형식
  1042→      case TYPE_ID.BUILTIN:
  1043→        return { tag: "builtin", name: payload };
  1044→      case TYPE_ID.ITER:
  1045→        return { tag: "iter", val: payload, idx: 0 };
  1046→      default:
  1047→        this.runtimeError(`Unknown heap type: ${typeId}`);
  1048→    }
